 const save=async()=>{if(!blob||!supabase)return setStatus("请先登录并完成 Supabase 配置。" );if(blob.size>recordBytes)return setStatus(`录音超过 ${recordBytes/1024/1024} MB，不能上传；请缩短后重录。` );setStatus("正在保存并检查云端额度…");const{data:{user}}=await supabase.auth.getUser();if(!user)return setStatus("请先登录账号，再保存录音。" );const existing=await supabase.from("speaking_recordings").select("id,storage_path,created_at").eq("user_id",user.id).order("created_at",{ascending:true});if(existing.error)return setStatus(`无法检查录音额度：${existing.error.message}`);const rows=existing.data||[],stale=rows.slice(0,Math.max(0,rows.length-(recordLimit-1))),ext=blob.type.includes("mp4")?"m4a":blob.type.includes("ogg")?"ogg":"webm",path=`${user.id}/${Date.now()}.${ext}`,upload=await supabase.storage.from("speaking-recordings").upload(path,blob,{contentType:blob.type,upsert:false});if(upload.error)return setStatus(`保存失败：${upload.error.message}`);const recordPrompt=`[${mode}] ${prompt}${transcript?`\nTranscript: ${transcript}`:""}`,row=await supabase.from("speaking_recordings").insert({user_id:user.id,storage_path:path,prompt:recordPrompt,duration_seconds:seconds});if(row.error){await supabase.storage.from("speaking-recordings").remove([path]);return setStatus(`记录失败：${row.error.message}`)}if(stale.length){await supabase.storage.from("speaking-recordings").remove(stale.map(x=>x.storage_path));await supabase.from("speaking_recordings").delete().in("id",stale.map(x=>x.id))}const count=Math.min(recordLimit,rows.length+1);setSavedCount(count);setStatus(`✓ 已保存到账号（${count}/${recordLimit}）；超过上限会自动删除最早录音`) };
