function SpeakingLab({sample,speak}:{sample:string;speak:(t:string,r?:number)=>void}){
 const[speed,setSpeed]=useState(.82),[pause,setPause]=useState(1800),[shadowing,setShadowing]=useState(false),[active,setActive]=useState(-1);
 const run=useRef(0);
 const chunks=sample.match(/[^.!?]+[.!?]+/g)||[sample];
 const shadow=async()=>{const id=++run.current;setShadowing(true);speechSynthesis.cancel();for(let i=0;i<chunks.length;i++){if(id!==run.current)break;setActive(i);await new Promise<void>(resolve=>{const u=new SpeechSynthesisUtterance(chunks[i].trim());setUtteranceVoice(u);u.rate=speed;u.pitch=1;u.onend=()=>resolve();u.onerror=()=>resolve();speechSynthesis.speak(u)});if(id!==run.current)break;await new Promise(r=>setTimeout(r,pause))}if(id===run.current){setShadowing(false);setActive(-1)}};
 const stopShadow=()=>{run.current++;speechSynthesis.cancel();setShadowing(false);setActive(-1)};
 return <div className="speakingLab"><div className="labHead"><div><b>🎧 影子跟读</b><span>{shadowing?`第 ${active+1}/${chunks.length} 句：听完后立即模仿`:`分意群听一句、模仿一句，再继续`}</span></div><div className="shadowSettings"><VoicePicker/><select aria-label="跟读速度" value={speed} onChange={e=>setSpeed(Number(e.target.value))}><option value="0.68">慢速 0.68×</option><option value="0.82">练习 0.82×</option><option value="1">正常 1.0×</option></select><select aria-label="模仿停顿" value={pause} onChange={e=>setPause(Number(e.target.value))}><option value="1200">停顿 1.2 秒</option><option value="1800">停顿 1.8 秒</option><option value="2600">停顿 2.6 秒</option></select></div></div><div className="shadowChunks">{chunks.map((x,i)=><button className={active===i?"active":""} key={i} onClick={()=>{stopShadow();setActive(i);speak(x.trim(),speed)}}><i>{active===i?"▶":i+1}</i>{x.trim()}<small>点击重听</small></button>)}</div><div className="labActions"><button className={shadowing?"stopShadow":"secondary"} onClick={shadowing?stopShadow:shadow}>{shadowing?"■ 停止跟读":"▶ 开始连续跟读"}</button></div><VoiceRecorder prompt={sample} reference={sample} defaultMode="shadow" title="录下跟读并纠正"/></div>;
}

const taskLessons:Record<number,{focus:string;rescue:string}>={
 1:{focus:"先给一个明确建议，再补理由、具体做法和鼓励；不需要把所有可能性都讲完。",rescue:"Another practical step you could take is..."},
 2:{focus:"永远沿时间线说：什么时候 → 遇到什么 → 我做了什么 → 结果和感受。忘记细节就继续说下一步。",rescue:"What happened next was that..."},
 3:{focus:"不要逐个物品点名。先总览，再按前景、背景和人物动作移动视线，最后做一个合理推测。",rescue:"Moving to the background, I can also see..."},
 4:{focus:"先预测最可能发生的一件事，再用画面证据证明，接着说人物反应和最终结果。",rescue:"Based on what I can see, the most likely outcome is..."},
 5:{focus:"开头十秒内必须选边。用两个共同标准比较，承认另一选项一个优点，再回扣自己的选择。",rescue:"Even though the other option has benefits, I'd still choose..."},
 6:{focus:"先表示理解，但不要放弃立场；说明问题造成的影响，提出一个可执行方案，并确认双方下一步。",rescue:"What I'm trying to suggest is a solution that works for both of us."},
 7:{focus:"先亮明同意或反对，再给两个理由和一个例子；最后用让步句承认例外并重申立场。",rescue:"The main point I'm trying to make is that..."},
 8:{focus:"先交代地点，再说最异常的主体；按左右、上下或远近补细节，最后描述人群反应或潜在风险。",rescue:"The strangest detail is that..."},
};
const generalRescue=["Let me put that another way.","What I mean is...","Another detail worth mentioning is...","So, going back to my main point..."];
function TaskCoach({task,score,speak}:{task:ExamTask;score:Band;speak:(t:string,r?:number)=>void}){const no=Number(task.type.match(/Task (\d)/)?.[1]||1),lesson=taskLessons[no];return <details className="taskCoach"><summary><span>这类题怎么答</span><b>万能骨架 + 卡壳救援</b><i>＋</i></summary><div className="coachBody"><section><small>固定四步路线</small><ol>{taskFrames[no].map(x=><li key={x}>{x}</li>)}</ol><p>{lesson.focus}</p></section><section><small>卡住时：停顿 → 换说法 → 兜回主线</small><div className="rescuePhrases">{[generalRescue[0],generalRescue[1],lesson.rescue,generalRescue[3]].map((x,i)=><button key={x} onClick={()=>speak(x)}><em>{i+1}</em><span>{x}</span><i>▶</i></button>)}</div><p className="scoreTarget"><b>{score}分目标：</b>{score===5?"守住四步，每步说一句清楚的句子。":score===6?"四步完整，并给出一个具体原因或例子。":"加入精确细节、让步和自然连接；卡壳后能主动回扣主线。"}</p></section></div></details>}

function ExamView({kind,index,step,score,setIndex,setStep,setScore,speak}:{kind:"celpip"|"ielts";index:number;step:"prompt"|"hint"|"answer"|"transfer";score:Band;setIndex:React.Dispatch<React.SetStateAction<number>>;setStep:React.Dispatch<React.SetStateAction<"prompt"|"hint"|"answer"|"transfer">>;setScore:React.Dispatch<React.SetStateAction<Band>>;speak:(t:string,r?:number)=>void}){
 const tasks=kind==="celpip"?examTasks:ieltsTasks,fiveSamples=kind==="celpip"?sample5s:ieltsSample5;
 const task=tasks[index%tasks.length],low=task.lowSample||fiveSamples[index%fiveSamples.length],high=task.sample,sample=scoredSample(kind,low,high,score);
 return <section className="exam"><div className="examIntro"><span>SPEAKING · ANTI-BLANK</span><h2>{kind==="celpip"?"CELPIP 全任务训练":"IELTS Part 1–3 训练"}</h2><p>不要追求完美。先用启动句抢回节奏，再沿四步骨架说满内容。</p><BandSelector kind={kind} score={score} setScore={setScore}/></div><article className="examCard"><div className="cardTop"><span>{task.type} · {index%tasks.length+1}/{tasks.length}</span><button onClick={()=>{setIndex(i=>(i+1)%tasks.length);setStep("prompt")}}>↝ 换一题</button></div><label>考试题目</label><h3>{task.question}</h3>{kind==="celpip"&&<TaskCoach task={task} score={score} speak={speak}/>}<div className="starter"><small>大脑空白时，只说这一句也算启动成功</small><b>{task.starter}</b><button className="sound" onClick={()=>speak(task.starter)}>▶ 听启动句</button></div>{kind==="celpip"&&<div className="rescueBar"><small>中间卡壳，不要停：</small>{["Let me put that another way.","So, going back to my main point..."].map(x=><button key={x} onClick={()=>speak(x)}>▶ {x}</button>)}</div>}{step==="prompt"?<div className="actionArea"><p>先立即说启动句，然后尝试自己补充 3 个要点。卡住就用救援句接回来。</p><div><button className="secondary" onClick={()=>setStep("hint")}>我卡住了 · 看表达库</button><button className="primary" onClick={()=>setStep("answer")}>我说完了 · 看示范</button></div></div>:step==="hint"?<div className="examFrame"><div className="levelNote"><b>{kind==="celpip"?`CELPIP ${score} 分任务句库`:`IELTS Band ${score} 回答句库`}</b><span>{score<=6?"优先把答案说清楚，并补充原因与例子":"增加句式变化、自然衔接和观点展开"}</span></div>{sentenceBank(kind,task.type,score).map((choices,i)=><ChoiceRow key={i} choices={choices} index={i} speak={speak}/>)}<button className="primary" onClick={()=>setStep("answer")}>任选表达说完 · 看示范</button></div>:<div className="answer"><label>{score} 分自然示范 <button className="sound" onClick={()=>speak(sample,.82)}>▶ 听完整回答</button></label><h4>{sample}</h4><SpeakingLab sample={sample} speak={speak}/><div className="repeat"><button className="secondary danger" onClick={()=>setStep("hint")}>还是会空白</button><button className="primary" onClick={()=>{setIndex(i=>(i+1)%tasks.length);setStep("prompt")}}>能沿骨架说出 ✓</button></div></div>}</article></section>;
}

