function VocabTest({speak}:{speak:(t:string,r?:number)=>void}){
 type Answer={word:string;level:VLevel;band:number;ok:boolean;meaningOk:boolean;usageOk:boolean;active:boolean;channel:"listening"|"reading"|"unknown";correct:string};
 const levels:VLevel[]=["A1","A2","B1","B2","C1"];
 const makeTest=(random=false,source:VocabItem[]=vocabBank)=>levels.flatMap(level=>{const pool=source.filter(x=>x[1]===level);return (random?[...pool].sort(()=>Math.random()-.5):pool).slice(0,6)});
 const makeStandardTest=(words:LibraryWord[],random=true)=>{const selected=Array.from({length:12},(_,i)=>{const pool=words.filter(x=>x.band===i+1);return (random?[...pool].sort(()=>Math.random()-.5):pool).slice(0,10)});return Array.from({length:10},(_,round)=>selected.map((bandWords,bandIndex)=>{const x=bandWords[round],pool=words.filter(w=>w.band===bandIndex+1&&w.word!==x.word),offset=(round*37+bandIndex*11)%Math.max(pool.length,1);return [x.word,x.level,x.translation,pool[offset]?.translation||"不确定",pool[(offset+29)%pool.length]?.translation||"不确定",pool[(offset+67)%pool.length]?.translation||"不确定",x.definition] as VocabItem})).flat()};
 const[index,setIndex]=useState(0),[stage,setStage]=useState<"audio"|"reading"|"recall"|"verify">("audio"),[answers,setAnswers]=useState<Answer[]>([]),[channel,setChannel]=useState<"listening"|"reading">("listening"),[recall,setRecall]=useState(""),[testItems,setTestItems]=useState<VocabItem[]>(()=>makeTest()),[bankOpen,setBankOpen]=useState(false),[query,setQuery]=useState(""),[library,setLibrary]=useState<LibraryWord[]>([]),[visible,setVisible]=useState(120);const done=index>=testItems.length;
 const libraryMap=useMemo(()=>new Map(library.map(x=>[x.word,x])),[library]);
 const libraryItems=useMemo(()=>{const groups=Object.fromEntries(levels.map(level=>[level,library.filter(x=>x.level===level).map(x=>x.translation)])) as Record<VLevel,string[]>;return library.map((x,i)=>{const peers=groups[x.level];return [x.word,x.level,x.translation,peers[(i+17)%peers.length],peers[(i+43)%peers.length],peers[(i+89)%peers.length],x.definition] as VocabItem})},[library]);
 useEffect(()=>{let live=true;fetch("/vocab-10000.json").then(r=>r.json()).then((data:{words:LibraryWord[]})=>{if(live)setLibrary(data.words)}).catch(()=>{});return()=>{live=false}},[]);
 useEffect(()=>{if(library.length&&index===0&&!answers.length){setTestItems(makeStandardTest(library,true))}},[library]);
 useEffect(()=>{if(stage==="audio"&&!done&&!bankOpen){const timer=setTimeout(()=>speak(testItems[index][0]),250);return()=>clearTimeout(timer)}},[stage,index,bankOpen,testItems]);
 const estimate=(pass:(a:Answer)=>boolean,chance:number)=>{if(answers.length<12)return null;let value=0,low=0,high=0;for(let band=1;band<=12;band++){const rows=answers.filter(a=>a.band===band),n=rows.length;if(!n)return null;const k=rows.filter(pass).length,p=k/n,z=1.96,den=1+z*z/n,center=(p+z*z/(2*n))/den,margin=z*Math.sqrt((p*(1-p)+z*z/(4*n))/n)/den,adjust=(x:number)=>Math.max(0,Math.min(1,(x-chance)/(1-chance)));value+=1000*adjust(p);low+=1000*adjust(center-margin);high+=1000*adjust(center+margin)}return {value:Math.round(value/100)*100,low:Math.round(low/100)*100,high:Math.round(high/100)*100}};
 const estimates={listening:estimate(a=>a.channel==="listening",.25),reading:estimate(a=>a.meaningOk,.5),active:estimate(a=>a.active,0),usable:estimate(a=>a.active&&a.usageOk,0)};
 if(bankOpen){const q=query.toLowerCase().trim(),fallback=vocabBank.map(([word,level,translation,,,,definition],i)=>({word,level,translation,definition,phonetic:"",pos:"",rank:0,tags:"",band:Math.floor(i/1000)+1} as LibraryWord)),source=library.length?library:fallback,filtered=source.filter(x=>(x.word+x.translation+x.level+x.pos+x.tags).toLowerCase().includes(q));return <section className="wordBank"><div className="bankHead"><div><span>ECDICT · OFFLINE WORD BANK</span><h2>分级词库 · {library.length||"12,000"} 词</h2><p>按当代/BNC 语料频率筛选，包含音标、中文义、词性、等级和考试标签；点击词条即可听发音。</p></div><button className="primary" onClick={()=>setBankOpen(false)}>返回测试</button></div><input value={query} onChange={e=>{setQuery(e.target.value);setVisible(120)}} placeholder="搜索英文、中文、词性、级别或考试标签"/><div className="bankStats"><span>找到 {filtered.length} 词</span><span>当前显示 {Math.min(visible,filtered.length)} 词</span></div><div className="bankGrid">{filtered.slice(0,visible).map(x=><button key={x.word} onClick={()=>speak(x.word)}><i>{x.level}</i><b>{x.word}</b><em>{x.phonetic&&`/${x.phonetic}/`} {x.pos}</em><span>{x.translation}</span><small>{x.definition||x.tags}</small></button>)}</div>{visible<filtered.length&&<button className="loadWords" onClick={()=>setVisible(v=>v+120)}>继续加载 120 词</button>}<p className="dataCredit">词典数据：ECDICT · MIT License</p></section>}
 if(done){const metrics=[{name:"阅读接受词汇",data:estimates.reading},{name:"听力接受词汇",data:estimates.listening},{name:"主动回忆词汇",data:estimates.active},{name:"可用词汇",data:estimates.usable}];return <section className="vocabResult"><span>STRATIFIED VOCABULARY ESTIMATE</span><h2>12频段标准测评 <em>120题完成</em></h2><p>每个1,000词频段抽测10题；阅读和听力选择题已校正猜测概率。区间为95%统计估计范围，不再用答对题数硬套等级。</p><div className="estimateGrid final">{metrics.map(x=><div key={x.name}><b>{x.name}</b><strong>{x.data?.value.toLocaleString()||"—"}</strong><span>{x.data?`95%范围 ${x.data.low.toLocaleString()}–${x.data.high.toLocaleString()}`:"数据不足"}</span></div>)}</div><div className="wrongWords"><h3>需要优先激活</h3>{answers.filter(a=>!a.active||!a.usageOk).slice(0,40).map(a=><button key={a.word} onClick={()=>speak(a.word)}><b>{a.word}</b><span>{a.channel==="unknown"?"尚未识别":a.active?"会想起，用法待巩固":"能认出，尚不能主动调用"}</span><i>▶</i></button>)}</div><button className="primary" onClick={()=>{setIndex(0);setStage("audio");setAnswers([]);setRecall("");setTestItems(library.length?makeStandardTest(library,true):makeTest(true))}}>重新抽取120题</button></section>}
 const [word,level,correct,w1,w2,w3,example]=testItems[index],meaningOptions=[correct,w1,w2,w3].map((_,i,a)=>a[(i+index)%4]),genericPeers=(libraryItems.length?libraryItems:vocabBank).filter(x=>x[1]===level&&x[0]!==word).slice(index%8,index%8+3).map(x=>x[0]),meta=libraryMap.get(word),band=meta?.band||0,posChoices=["名词","动词","形容词","副词","介词","连词","其他"],otherPos=posChoices.filter(x=>x!==meta?.pos).slice(index%3,index%3+3),check:VocabCheck=vocabChecks[word]||(meta?{kind:"词性",prompt:`根据词典语料，${word} 最常见的词性是？`,correct:meta.pos,options:[meta.pos,...otherPos]}:{kind:"语境",prompt:example.replace(new RegExp(word,"i"),"_____"),correct:word,options:[word,...genericPeers]}),verifyOptions=check.options.map((_,i,a)=>a[(i+index+1)%4]);
 const next=(row:Answer)=>{setAnswers(a=>[...a,row]);setStage("audio");setRecall("");setIndex(i=>i+1)};
 const chooseMeaning=(picked:string)=>{if(picked===correct){setChannel(stage==="audio"?"listening":"reading");setStage("recall")}else if(stage==="audio")setStage("reading");else next({word,level,band,ok:false,meaningOk:false,usageOk:false,active:false,channel:"unknown",correct})};
 const submitRecall=()=>setStage("verify");
 const answerVerify=(picked:string)=>{const active=recall.trim().toLowerCase()===word.toLowerCase(),usageOk=picked===check.correct;next({word,level,band,ok:active&&usageOk,meaningOk:true,usageOk,active,channel,correct})};
 const blank=new RegExp(word+(word==="delay"?"ed":""),"i").test(example)?example.replace(new RegExp(word+(word==="delay"?"ed":""),"i"),"_____"):"不给英文提示：只根据中文释义回忆并输入这个单词。";
 const stepNo=stage==="audio"?1:stage==="reading"?2:stage==="recall"?3:4;
 return <section className="vocabTest"><aside><span>12-BAND STANDARD TEST</span><h2>分层词汇量测评</h2><p>12个千词频段各抽10题。边测边估算，并显示95%范围；完成越多，范围越窄。</p><button className="bankLink" onClick={()=>setBankOpen(true)}>浏览完整分级词库 · {library.length?library.length.toLocaleString():"12,000"}</button><div className="vocabMeter"><b>{index+1}/{testItems.length}</b><i><span style={{width:`${index/testItems.length*100}%`}}/></i></div><small>词频段 · {band||"载入中"}K · {level}</small><div className="verifySteps four">{["听","看","想","用"].map((x,i)=><b key={x} className={stepNo>=i+1?"active":""}>{i+1} {x}</b>)}</div><div className="liveEstimate"><small>动态估算 · 已完成 {answers.length} 题</small>{estimates.reading?<><div><span>阅读</span><b>{estimates.reading.value.toLocaleString()}</b></div><div><span>听力</span><b>{estimates.listening?.value.toLocaleString()}</b></div><div><span>主动</span><b>{estimates.active?.value.toLocaleString()}</b></div><div><span>可用</span><b>{estimates.usable?.value.toLocaleString()}</b></div><em>当前95%范围较宽，完成120题后最稳定</em></>:<p>至少完成每个频段1题（共12题）后开始显示。</p>}</div></aside><article><div className="cardTop"><span>{band?`${band}K 词频段`:level} · 第 {stepNo} 关</span>{stage==="audio"&&<button onClick={()=>speak(word)}>↻ 再听一次</button>}</div>{stage==="audio"?<><label>不要看拼写，只根据发音选择含义</label><button className="audioOrb" onClick={()=>speak(word)}>▶</button><div className="vocabOptions">{meaningOptions.map(x=><button key={x} onClick={()=>chooseMeaning(x)}>{x}</button>)}<button className="unsure" onClick={()=>chooseMeaning("不确定")}>听不出来 · 看拼写</button></div></>:stage==="reading"?<><label>现在看拼写，再选择含义</label><h3>{word}</h3><p className="wordExample">{example}</p><div className="vocabOptions">{meaningOptions.map(x=><button key={x} onClick={()=>chooseMeaning(x)}>{x}</button>)}<button className="unsure" onClick={()=>chooseMeaning("不确定")}>仍然不认识</button></div></>:stage==="recall"?<><label>主动回忆 · 不显示英文，也不播放发音</label><h3 className="recallMeaning">{correct}</h3><p className="verifyPrompt">{blank}</p><input className="recallInput" autoFocus value={recall} onChange={e=>setRecall(e.target.value)} onKeyDown={e=>e.key==="Enter"&&submitRecall()} placeholder="输入你想起的英文单词"/><button className="primary recallNext" onClick={submitRecall}>确认 · 验证属性</button></>:<><label>{check.kind}验证 · 最后一关</label><h3 className="verifyWord">{word}</h3><p className="verifyPrompt">{check.prompt}</p><div className="vocabOptions verifyOptions">{verifyOptions.map(x=><button key={x} onClick={()=>answerVerify(x)}>{x}</button>)}<button className="unsure" onClick={()=>answerVerify("不确定")}>我不确定</button></div></>}</article></section>;
}

export default function Home(){
 const[mode,setMode]=useState<"practice"|"quiz"|"game"|"review"|"builder"|"vocab"|"exam"|"ielts">("practice"),[scene,setScene]=useState("全部"),[index,setIndex]=useState(0),[step,setStep]=useState<"prompt"|"hint"|"answer"|"transfer">("prompt"),[progress,setProgress]=useState<Progress>({}),[streak,setStreak]=useState(0),[lives,setLives]=useState(3),[stage,setStage]=useState(1),[score,setScore]=useState<Band>(5),[user,setUser]=useState<User|null>(null);
 useEffect(()=>{try{setProgress(JSON.parse(localStorage.getItem("chunk-srs")||"{}"))}catch{}},[]);
 useEffect(()=>{if(!supabase)return;supabase.auth.getUser().then(({data})=>setUser(data.user));const{data:{subscription}}=supabase.auth.onAuthStateChange((_event,session)=>setUser(session?.user||null));return()=>subscription.unsubscribe()},[]);
 useEffect(()=>{if(!user||!supabase)return;supabase.from("learning_progress").select("card_id,level,due,misses").eq("user_id",user.id).then(({data})=>{if(!data?.length)return;const cloud=Object.fromEntries(data.map(x=>[x.card_id,{level:x.level,due:Number(x.due),misses:x.misses}]));setProgress(local=>{const merged={...local,...cloud};localStorage.setItem("chunk-srs",JSON.stringify(merged));return merged})})},[user]);
 const due=useMemo(()=>cards.map((_,i)=>i).filter(i=>!progress[i]||progress[i].due<=Date.now()),[progress]);
 const pool=useMemo(()=>{let ids=cards.map((_,i)=>i).filter(i=>scene==="全部"||cards[i].scene===scene);if(mode==="review")ids=ids.filter(i=>due.includes(i));if(mode==="game")ids=ids.slice((stage-1)*10,stage*10);return ids.length?ids:[0]},[scene,mode,due,stage]);
 const id=pool[index%pool.length],card=cards[id];
 const speak=(t:string,r=.88)=>{speechSynthesis.cancel();const u=new SpeechSynthesisUtterance(t);setUtteranceVoice(u);u.rate=r;u.pitch=1;speechSynthesis.speak(u)};
 const setModeSafe=(m:typeof mode)=>{setMode(m);setIndex(0);setStep("prompt");setLives(3)};
 const grade=(ok:boolean)=>{const old=progress[id]||{level:0,due:0,misses:0};const level=ok?Math.min(old.level+1,5):0;const row={level,due:Date.now()+[0,1,3,7,14,30][level]*86400000,misses:old.misses+(ok?0:1)};const next={...progress,[id]:row};setProgress(next);localStorage.setItem("chunk-srs",JSON.stringify(next));if(user&&supabase)void supabase.from("learning_progress").upsert({user_id:user.id,card_id:id,...row,updated_at:new Date().toISOString()});setStreak(ok?streak+1:0);if(mode==="game"&&!ok)setLives(l=>l-1);if(mode==="game"&&ok&&(index+1)%10===0)setStage(s=>Math.min(s+1,Math.ceil(cards.length/10)));setIndex(i=>(i+1)%pool.length);setStep("prompt")};
 const mastered=Object.values(progress).filter(x=>x.level>=3).length;
 return <main><header><div className="brand"><span className="logo">C</span><div><strong>Chunk Talk</strong><small>地道生活英语 · 间隔复习</small></div></div><div className="headerRight"><div className="progress"><span>连胜 <b>{streak}</b></span><span>待复习 <b>{due.length}</b></span><span>已掌握 <b>{mastered}</b>/{cards.length}</span></div><AccountPanel user={user}/></div></header>
 <section className="hero compact"><div><span className="eyebrow">DAILY SPEAKING LAB</span><h1>把生活里要说的话，<em>练到脱口而出。</em></h1><p>共 {cards.length} 道地道表达，覆盖 {scenes.length-1} 类生活场景。不会的题会自动进入复习队列。</p></div>{mode==="game"?<div className="gameStat"><b>第 {stage} 关</b><span>{"❤️".repeat(Math.max(lives,0))}{"🖤".repeat(Math.max(3-lives,0))}</span></div>:<div className="today"><b>{due.length} 题待复习</b><span>记忆需要反复提取，而不是反复看答案</span></div>}</section>
 <div className="modes"><button className={mode==="practice"?"active":""} onClick={()=>setModeSafe("practice")}>🎙 自由练习</button><button className={mode==="quiz"?"active":""} onClick={()=>setModeSafe("quiz")}>✍️ 答题模式</button><button className={mode==="review"?"active":""} onClick={()=>setModeSafe("review")}>🧠 今日复习 <i>{due.length}</i></button><button className={mode==="builder"?"active":""} onClick={()=>setModeSafe("builder")}>🧩 英语思维组句</button><button className={mode==="vocab"?"active":""} onClick={()=>setModeSafe("vocab")}>📚 词汇量测试</button><button className={mode==="game"?"active":""} onClick={()=>setModeSafe("game")}>🎮 闯关模式</button><button className={mode==="exam"?"active":""} onClick={()=>setModeSafe("exam")}>🎯 CELPIP 全 8 Part</button><button className={mode==="ielts"?"active":""} onClick={()=>setModeSafe("ielts")}>🌍 IELTS Part 1–3</button></div>
 {mode!=="exam"&&mode!=="ielts"&&mode!=="builder"&&mode!=="vocab"&&<nav>{scenes.map(s=><button key={s} className={scene===s?"active":""} onClick={()=>{setScene(s);setIndex(0);setStep("prompt")}}>{s}</button>)}</nav>}
 {mode==="exam"?<ExamView kind="celpip" index={index} step={step} score={score} setIndex={setIndex} setStep={setStep} setScore={setScore} speak={speak}/>:mode==="ielts"?<ExamView kind="ielts" index={index} step={step} score={score} setIndex={setIndex} setStep={setStep} setScore={setScore} speak={speak}/>:mode==="builder"?<SentenceBuilder speak={speak}/>:mode==="vocab"?<VocabTest speak={speak}/>:mode==="game"&&lives<=0?<section className="gameOver"><span>💥</span><h2>本关挑战结束</h2><p>错题已经加入复习队列。复习后再来，会明显轻松。</p><button className="primary" onClick={()=>{setLives(3);setIndex(0)}}>重新挑战</button></section>:<section className="practice"><aside><span className="sceneIcon">{card.icon}</span><span className="sceneName">{card.scene}</span><h2>{card.context}</h2><div className="instruction"><span>1</span><p><b>{mode==="quiz"?"先完整作答":"先大声说"}</b><br/>不要逐词翻译，先把意思表达出来。</p></div><div className="instruction"><span>2</span><p><b>按真实熟练度评分</b><br/>“不熟”会在今天再次出现。</p></div></aside><article className="card"><div className="cardTop"><span>{mode==="game"?`第 ${stage} 关 · ${index%10+1}/10`:`第 ${index%pool.length+1}/${pool.length} 题`}</span><button onClick={()=>{setIndex(Math.floor(Math.random()*pool.length));setStep("prompt")}}>↝ 换一道</button></div><label>你想表达</label><h3>{card.prompt}</h3>
 <VoiceRecorder compact prompt={card.prompt} reference={card.answer}/>
 {step==="prompt"&&<div className="actionArea"><p>{mode==="quiz"?"请先完整说出英文，再核对答案。":"现在，大声说出来。"}</p><div><button className="secondary" onClick={()=>setStep("hint")}>给我一点提示</button><button className="primary" onClick={()=>setStep("answer")}>说完了 · 核对答案</button></div></div>}
 {step==="hint"&&<div className="hint"><label>关键词</label><p>{card.hint}</p><button className="primary" onClick={()=>setStep("answer")}>核对答案</button></div>}
 {(step==="answer"||step==="transfer")&&<div className="answer"><label>自然表达 <button className="sound" onClick={()=>speak(card.answer)}>▶ 听一遍</button></label><h4>{card.answer}</h4><div className="chunks"><div><b>{card.hint.split(" / ")[0]}</b><span>优先整块记忆</span></div><div><b>Level {progress[id]?.level||0}/5</b><span>当前记忆强度</span></div></div>{step==="answer"&&<div className="repeat"><button onClick={()=>speak(card.answer,.68)}>🐢 慢速</button><button onClick={()=>speak(card.answer)}>▶ 正常</button><button className="primary" onClick={()=>setStep("transfer")}>跟读完成 · 迁移</button></div>}</div>}
 {step==="transfer"&&<div className="transfer"><label>迁移挑战 · 不看原句</label><p>{card.followUp}</p><div><button className="secondary danger" onClick={()=>grade(false)}>还不熟 · 加入复习</button><button className="primary" onClick={()=>grade(true)}>能自然说出 ✓</button></div></div>}</article></section>}
 <footer><span>间隔：当天 → 1 天 → 3 天 → 7 天 → 14 天 → 30 天</span><span>学习进度保存在当前设备</span></footer></main>
}
